      icon: this.sanitizer.bypassSecurityTrustHtml(this.generateVehicleSVG(vehicle.id, 0))
    }));
  }

  selectVehicle(vehicle: VehicleType) {
    this.selectedVehicle = vehicle;
    this.currentRotation = 0;
    this.selectedEquipment = [];
  }

  toggleEquipment(item: Equipment) {
    const index = this.selectedEquipment.findIndex(eq => eq.id === item.id);
    if (index > -1) {
      this.selectedEquipment.splice(index, 1);
    } else {
      this.selectedEquipment.push(item);
    }
  }

  isEquipmentSelected(id: string): boolean {
    return this.selectedEquipment.some(eq => eq.id === id);
  }

  rotateVehicle(direction: 'left' | 'right') {
    if (direction === 'left') {
      this.currentRotation = (this.currentRotation - 90 + 360) % 360;
    } else {
      this.currentRotation = (this.currentRotation + 90) % 360;
    }
  }

  getRotatedVehicle(): SafeHtml {
    if (!this.selectedVehicle) return '';
    return this.sanitizer.bypassSecurityTrustHtml(
      this.generateVehicleSVG(this.selectedVehicle.id, this.currentRotation)
    );
  }

  generateVehicleSVG(type: string, rotation: number): string {
    const baseColor = '#546e7a';
    const accentColor = '#E5C643';
    const windowColor = '#90caf9';

    let view = 'side-left';
    if (rotation === 90) view = 'front';
    else if (rotation === 180) view = 'side-right';
    else if (rotation === 270) view = 'rear';

    switch (type) {
      case 'sedan':
        return this.getSedanSVG(view, baseColor, accentColor, windowColor);
      case 'suv':
        return this.getSUVSVG(view, baseColor, accentColor, windowColor);
      case 'todoterreno':
        return this.getTodoterrenoSVG(view, baseColor, accentColor, windowColor);
      case 'pickup':
        return this.getPickupSVG(view, baseColor, accentColor, windowColor);
      case 'hatchback':
        return this.getHatchbackSVG(view, baseColor, accentColor, windowColor);
      default:
        return '';
    }
  }

