    if (view === 'front' || view === 'rear') {
      return `
        <svg viewBox="0 0 200 120" xmlns="http://www.w3.org/2000/svg">
          <rect x="40" y="40" width="120" height="60" fill="${baseColor}" rx="10"/>
          <rect x="50" y="30" width="100" height="40" fill="${windowColor}" opacity="0.7" rx="5"/>
          <circle cx="50" cy="95" r="15" fill="#2c3e50"/>
          <circle cx="150" cy="95" r="15" fill="#2c3e50"/>
          <circle cx="50" cy="95" r="8" fill="${accentColor}"/>
          <circle cx="150" cy="95" r="8" fill="${accentColor}"/>
